```csharp
class Dyr { public virtual void Snakk() {} }

class Hund : Dyr
{
    public override void Snakk() => Console.WriteLine("Voff!");
}
class Katt : Dyr
{
    public override void Snakk() => Console.WriteLine("Mjau!");
}

Dyr[] dyr = { new Hund(), new Katt() };
foreach (var d in dyr) d.Snakk();
// Output: Voff!  Mjau!
```

```csharp
abstract class Figur
{
    public abstract double Areal(); // hva vi KAN gjøre
}

class Sirkel : Figur
{
    private double radius;
    public Sirkel(double r) { radius = r; }
    public override double Areal() => Math.PI * radius * radius;
}

Figur f = new Sirkel(5);
Console.WriteLine(f.Areal()); // vi bruker det, uten å kjenne detaljene
```

