```csharp
void Hils()
{
    Console.WriteLine("Hei, verden!");
}

void Hils(string navn)
{
    Console.WriteLine($"Hei, {navn}!");
}

void Hils(string navn, string tittel)
{
    Console.WriteLine($"Hei, {tittel} {navn}!");
}

Hils();                   // Hei, verden!
Hils("Ada");              // Hei, Ada!
Hils("Lovelace", "fru"); // Hei, fru Lovelace!
```

